const body = $input.first().json.body;
const headers = $input.first().json.headers;

// Auth check
if (headers['x-widget-token'] !== process.env.WIDGET_AUTH_TOKEN) {
  throw new Error('UNAUTHORIZED');
}

// Validate message
if (!body.message || typeof body.message !== 'string' || body.message.trim().length === 0) {
  throw new Error('Message is required and must not be empty');
}
if (body.message.length > 1000) {
  throw new Error('Message must not exceed 1000 characters');
}

// Validate session_id
if (!body.session_id || typeof body.session_id !== 'string') {
  throw new Error('session_id is required');
}

// Validate consent
if (body.consent !== true) {
  throw new Error('Consent must be given (consent: true)');
}

// Hash IP
const crypto = require('crypto');
const ip = headers['x-forwarded-for'] || headers['x-real-ip'] || 'unknown';
const ipHash = crypto.createHash('sha256').update(ip).digest('hex');

// Rate limiting
const staticData = getWorkflowStaticData('global');
if (!staticData.rateLimits) staticData.rateLimits = {};
const now = Date.now();
const windowMs = (parseInt(process.env.RATE_LIMIT_WINDOW_MINUTES) || 10) * 60 * 1000;
const maxRequests = parseInt(process.env.RATE_LIMIT_PER_IP) || 20;

// Clean old entries
if (staticData.rateLimits[ipHash]) {
  staticData.rateLimits[ipHash] = staticData.rateLimits[ipHash].filter(ts => now - ts < windowMs);
}
const requests = staticData.rateLimits[ipHash] || [];
if (requests.length >= maxRequests) {
  throw new Error('RATE_LIMITED');
}
requests.push(now);
staticData.rateLimits[ipHash] = requests;

return [{
  json: {
    session_id: body.session_id,
    message: body.message,
    ipHash,
    consent: body.consent,
    page_url: body.page_url || ''
  }
}];

// History comes from Load History node
const historyNode = $('Load History').all();
const history = Array.isArray(historyNode) ? historyNode.map(item => item.json) : [];

// KB comes from Load Knowledge Base node
const kbNode = $('Load Knowledge Base').all();
const kbEntries = Array.isArray(kbNode) ? kbNode.map(item => item.json) : [];

// Format KB content
let kbContent = '';
let currentCategory = '';
for (const entry of kbEntries) {
  if (entry.category !== currentCategory) {
    currentCategory = entry.category;
    kbContent += '\n--- ' + currentCategory.toUpperCase().replace(/_/g, ' ') + ' ---\n';
  }
  kbContent += entry.title + ': ' + entry.content;
  if (entry.url) kbContent += ' (Mehr Infos: ' + entry.url + ')';
  kbContent += '\n';
}

