{KB_CONTENT}`.replace('{KB_CONTENT}', kbContent);

// Build messages array from history
const messages = [];
for (const msg of history) {
  // Only include if it looks like a valid chat message from Supabase
  if (msg.role && msg.content) {
    messages.push({ role: msg.role, content: msg.content });
  }
}

// Add current user message
const currentMessage = $('Validate & Rate Limit').first().json.message;
messages.push({ role: 'user', content: currentMessage });

return [{
  json: {
    model: 'claude-sonnet-4-6',
    max_tokens: 800,
    system: systemPrompt,
    messages: messages,
    _session_id: $('Validate & Rate Limit').first().json.session_id,
    _user_message: currentMessage,
    _ip_hash: $('Validate & Rate Limit').first().json.ipHash
  }
}];

const sessionId = $('Build Claude Payload').first().json._session_id;
const userMessage = $('Build Claude Payload').first().json._user_message;

return [{
  json: {
    content: [{ type: 'text', text: 'Unser KI-Assistent ist gerade nicht erreichbar. Bitte kontaktieren Sie uns direkt unter +43 (0) 1 21 22 446 oder per E-Mail an team@rollomax.at. Wir helfen Ihnen gerne persoenlich weiter.' }],
    _session_id: sessionId,
    _user_message: userMessage,
    _is_fallback: true
  }
}];

const input = $input.first().json;
let responseText = '';

// Handle both normal response and fallback
if (input._is_fallback) {
  responseText = input.content[0].text;
} else {
  // Normal Claude response
  responseText = input.content[0].text;
}

// Parse lead data from Claude's response
const leadMatch = responseText.match(/<!--LEAD:(.*?)-->/);
let leadData = null;
let cleanReply = responseText;

if (leadMatch) {
  try {
    leadData = JSON.parse(leadMatch[1]);
    cleanReply = responseText.replace(/<!--LEAD:.*?-->/, '').trim();
  } catch(e) {
    leadData = null;
  }
}

// Get passthrough data
const sessionId = input._session_id || $('Build Claude Payload').first().json._session_id;
const userMessage = input._user_message || $('Build Claude Payload').first().json._user_message;

return [{
  json: {
    reply: cleanReply,
    session_id: sessionId,
    user_message: userMessage,
    has_lead_data: leadData !== null,
    lead_data: leadData
  }
}];

const body = $input.first().json.body;
const headers = $input.first().json.headers;

// Auth check
if (headers['x-widget-token'] !== process.env.WIDGET_AUTH_TOKEN) {
  throw new Error('UNAUTHORIZED');
}

// Validate session_id
if (!body.session_id || typeof body.session_id !== 'string') {
  throw new Error('session_id is required');
}

return [{
  json: {
    session_id: body.session_id
  }
}];
